const clients = $input.all()
  .filter(item => String(item.json.active).toUpperCase() === 'TRUE')
  .map(item => {
    const cfg = item.json;
    const isProd = cfg.environment === 'production';
    return { json: {
      ...cfg,
      qb_base_url: isProd ? 'https://quickbooks.api.intuit.com' : 'https://sandbox-quickbooks.api.intuit.com',
      qb_payment_link_base: isProd ? 'https://app.qbo.intuit.com' : 'https://sandbox.qbo.intuit.com',
      effective_environment: cfg.environment || 'sandbox',
      qb_minor_version: parseInt(cfg.qb_minor_version || '73', 10)
    }};
  });
if (!clients.length) throw new Error('No active clients in Client_Master_Config');
console.log(`WF3A: Processing ${clients.length} client(s)`);
return clients;

const allCreds = $input.all();
const productionCreds = allCreds.filter(item => item.json.credential_name === 'production');
if (productionCreds.length === 0) throw new Error('No production credential found in OAuth sheet');
productionCreds.sort((a, b) => new Date(b.json.last_updated || '2000-01-01') - new Date(a.json.last_updated || '2000-01-01'));
const latest = productionCreds[0];
console.log('Using credential last updated:', latest.json.last_updated);
return [latest];

const oauthResponse = $input.first().json;
const accessToken = oauthResponse.access_token;
const refreshToken = oauthResponse.refresh_token;
const expiresIn = oauthResponse.expires_in;
if (!accessToken) throw new Error('No access_token in OAuth response: ' + JSON.stringify(oauthResponse));
const expiresAt = new Date(Date.now() + (expiresIn * 1000));
console.log('Token refreshed. Expires at:', expiresAt.toISOString());
return [{ json: {
  access_token: accessToken,
  refresh_token: refreshToken,
  token_type: 'Bearer',
  expires_in: expiresIn,
  expires_at: expiresAt.toISOString(),
  retrieved_at: new Date().toISOString(),
  authorization_header: `Bearer ${accessToken}`
}}];

// Merge client config + fresh token into one object for all downstream nodes.
// Reference in downstream: $('Merge Config + Token').first().json.qb_realm_id
const token = $input.first().json;
const config = $('Loop: Process Each Client').item.json;
if (!token.access_token) throw new Error(`OAuth token missing for ${config.client_name}`);
return [{ json: { ...config, ...token, authorization_header: `Bearer ${token.access_token}` }}];

// Extract and flatten invoice data from QB response.
// FIX: Added EmailStatus = NeedToSend filter in query above,
// but this code also checks as a second safety layer.
const config = $('Merge Config + Token').first().json;
const items = $input.all();
const invoices = [];

for (const item of items) {
  const responseData = Array.isArray(item.json) ? item.json[0] : item.json;
  const queryResponse = responseData.QueryResponse;
  if (queryResponse && queryResponse.Invoice) {
    for (const invoice of queryResponse.Invoice) {
      // Idempotency guard: skip if already sent
      if (invoice.EmailStatus === 'EmailSent') {
        console.log(`Skipping already-sent invoice: ${invoice.DocNumber}`);
        continue;
      }
      if (!invoice.BillEmail?.Address) continue;

      const qbPaymentLink = invoice.InvoiceLink ||
        `${config.qb_payment_link_base}/qbo65/pay/invoice/${invoice.Id}`;

      invoices.push({ json: {
        invoice_id: invoice.Id,
        invoice_number: invoice.DocNumber,
        sync_token: invoice.SyncToken,
        customer_name: invoice.CustomerRef?.name || 'Unknown',
        customer_id: invoice.CustomerRef?.value || '',
        customer_email: invoice.BillEmail.Address,
        total_amount: parseFloat(invoice.TotalAmt || 0),
        balance: parseFloat(invoice.Balance || 0),
        currency: invoice.CurrencyRef?.value || 'USD',
        invoice_date: invoice.TxnDate,
        due_date: invoice.DueDate,
        created_time: invoice.MetaData.CreateTime,
        qb_payment_link: qbPaymentLink,
        online_payments_enabled: invoice.AllowOnlinePayment !== false,
        credit_card_enabled: invoice.AllowOnlineCreditCardPayment !== false,
        ach_enabled: invoice.AllowOnlineACHPayment !== false,
        email_status: invoice.EmailStatus || 'NeedToSend',
        processed_timestamp: new Date().toISOString(),
        // Pass client context forward
        client_id: config.client_id,
        client_name: config.client_name
      }});
    }
  }
}

if (invoices.length === 0) {
  return [{ json: { no_new_invoices: true, checked_at: new Date().toISOString(), client_id: config.client_id } }];
}

console.log(`Found ${invoices.length} invoice(s) to process for ${config.client_name}`);
return invoices;

// Log payment link data to Google Sheets.
// FIX v2.1: upsert key changed from payment_link_id to qb_invoice_id.
const invoiceData = $input.first().json;
return { json: {
  timestamp: new Date().toISOString(),
  qb_invoice_id: invoiceData.invoice_id,
  qb_invoice_number: invoiceData.invoice_number,
  customer_name: invoiceData.customer_name,
  customer_email: invoiceData.customer_email,
  amount: invoiceData.balance,
  qb_payment_link: invoiceData.qb_payment_link,
  status: 'sent',
  created_date: new Date().toISOString().split('T')[0],
  online_payments_enabled: invoiceData.online_payments_enabled,
  payment_methods: [invoiceData.credit_card_enabled ? 'Credit Card' : null, invoiceData.ach_enabled ? 'ACH' : null].filter(Boolean).join(', '),
  email_status: invoiceData.email_status,
  client_id: invoiceData.client_id,
  notes: 'QB tracks payment automatically via Balance field'
}};

const invoiceData = $input.item.json;
const invoiceNumber = invoiceData.invoice_number || 'N/A';
const balance = parseFloat(invoiceData.balance || 0);
const totalAmount = parseFloat(invoiceData.total_amount || 0);
const dueDate = invoiceData.due_date || 'N/A';
const txnDate = invoiceData.invoice_date || 'N/A';
const customerName = invoiceData.customer_name || 'Valued Customer';
const customerEmail = invoiceData.customer_email || '';
const qbPaymentLink = invoiceData.qb_payment_link || 'Contact us for payment details';
const creditCardEnabled = invoiceData.credit_card_enabled || false;
const achEnabled = invoiceData.ach_enabled || false;

const emailBody = `Dear ${customerName},

Thank you for your business! Your invoice is ready for payment.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📄 INVOICE DETAILS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

Invoice Number: ${invoiceNumber}
Amount Due: $${balance.toFixed(2)}
Invoice Date: ${txnDate}
Due Date: ${dueDate}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🔒 PAY SECURELY ONLINE
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

Click here to pay now:
${qbPaymentLink}

Accepted Payment Methods:
${creditCardEnabled ? '💳 Credit/Debit Card\n' : ''}${achEnabled ? '🏦 ACH Bank Transfer\n' : ''}
✓ Secure payment powered by Intuit QuickBooks
✓ Instant confirmation & receipt

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

Alternative Payment Methods:
- Zelle: payments@lunarlogic.ai
- Check: Mail to address on invoice

Questions? Reply to this email.

Best regards,
LunarLogic Accounting Team`;

return { json: {
  invoice_id: invoiceData.invoice_id,
  invoice_number: invoiceNumber,
  customer_email: customerEmail,
  customer_name: customerName,
  balance: balance.toFixed(2),
  total_amount: totalAmount.toFixed(2),
  invoice_date: txnDate,
  due_date: dueDate,
  subject: `Invoice ${invoiceNumber} - $${balance.toFixed(2)} Due ${dueDate}`,
  email_body: emailBody,
  qb_payment_link: qbPaymentLink,
  invoice_id_for_url: invoiceData.invoice_id,
  credit_card_enabled: creditCardEnabled,
  ach_enabled: achEnabled
}};

