// FIX v2.1: Changed $('Calculate Invoice') to $('Extract Invoice Data').
// That node does not exist in WF3A — previous version would crash on error path.
const errorData = $input.first().json.error;
let httpCode = errorData?.httpCode || errorData?.statusCode || 'unknown';
const errorMessage = errorData?.message || JSON.stringify(errorData);
const fullErrorStr = JSON.stringify(errorMessage).toLowerCase();
const hasInvalidGrant = fullErrorStr.includes('invalid_grant') || fullErrorStr.includes('invalid refresh token');
const hasAuthFailed = fullErrorStr.includes('authenticationfailed');

if (httpCode === 'unknown' && fullErrorStr.includes('400')) httpCode = '400';
else if (fullErrorStr.includes('401')) httpCode = '401';

let errorType, isRetriable, severity, actionRequired;
if (httpCode === '400' && hasInvalidGrant) {
  errorType = 'OAUTH_REFRESH_TOKEN_EXPIRED'; isRetriable = false; severity = 'critical';
  actionRequired = 'QuickBooks refresh token expired. Manually update token in the QB OAuth credentials sheet and retry.';
} else if (httpCode === '401' || hasAuthFailed) {
  errorType = 'AUTH_FAILED'; isRetriable = true; severity = 'error';
  actionRequired = 'QB authentication failed. Retrying...';
} else if (httpCode === '429') {
  errorType = 'RATE_LIMIT'; isRetriable = true; severity = 'warning';
  actionRequired = 'QB rate limit hit. Waiting for next run.';
} else {
  errorType = 'UNKNOWN'; isRetriable = false; severity = 'error';
  actionRequired = 'Unknown error. Manual investigation required.';
}

const clientCtx = $('Loop: Process Each Client').item?.json || {};

return [{ json: {
  error_type: errorType, http_code: httpCode,
  error_message: errorMessage, is_retriable: isRetriable,
  severity, action_required: actionRequired,
  retry_count: 0,
  client_id: clientCtx.client_id, client_name: clientCtx.client_name,
  workflow: 'WF3A', timestamp: new Date().toISOString()
}}];

// Circuit breaker: max 3 retries before routing to Dead Letter Queue.
const errorInfo = $input.first().json;
const retryCount = (errorInfo.retry_count || 0) + 1;
const maxRetries = 3;
return [{ json: {
  ...errorInfo,
  retry_count: retryCount,
  circuit_breaker_tripped: retryCount >= maxRetries,
  circuit_breaker_message: retryCount >= maxRetries
    ? `Max retries (${maxRetries}) reached for error: ${errorInfo.error_type}`
    : `Retry ${retryCount} of ${maxRetries}`
}}];
